import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Home.css';

const features = [
  {
    icon: '✦',
    title: 'Expertise reconnue',
    text: "Une équipe de praticiens qualifiés avec plus de 20 ans d'expérience.",
  },
  {
    icon: '◎',
    title: 'Technologies avancées',
    text: 'Des équipements modernes pour un diagnostic précis et des soins confortables.',
  },
  {
    icon: '◇',
    title: 'Service premium',
    text: 'Un accompagnement personnalisé dans un environnement élégant et rassurant.',
  },
  {
    icon: '◷',
    title: 'Horaires flexibles',
    text: 'Ouvert 6 jours sur 7 avec des créneaux adaptés à votre rythme.',
  },
];

const treatments = [
  {
    icon: '✧',
    tag: 'Esthétique',
    title: 'Blanchiment dentaire',
    text: "Un sourire plus lumineux avec un protocole professionnel rapide et efficace.",
  },
  {
    icon: '◌',
    tag: 'Esthétique',
    title: 'Facettes céramiques',
    text: 'Des facettes fines et naturelles pour harmoniser la forme et la teinte des dents.',
  },
  {
    icon: '⬢',
    tag: 'Implantologie',
    title: 'Implants dentaires',
    text: 'Une solution durable et esthétique pour remplacer une ou plusieurs dents.',
  },
  {
    icon: '☰',
    tag: 'Orthodontie',
    title: 'Orthodontie invisible',
    text: 'Des aligneurs transparents pour corriger l’alignement en toute discrétion.',
  },
  {
    icon: '♡',
    tag: 'Parodontologie',
    title: 'Soins des gencives',
    text: 'Prévenir, stabiliser et traiter les problèmes gingivaux sur le long terme.',
  },
  {
    icon: '▣',
    tag: 'Prothèse',
    title: 'Couronnes & bridges',
    text: 'Des restaurations sur mesure alliant résistance, confort et esthétique.',
  },
];

const testimonials = [
  {
    name: 'Samira El Mansouri',
    role: "Cheffe d'entreprise",
    text: 'Une expérience exceptionnelle. L’équipe est douce, professionnelle et le résultat est magnifique.',
  },
  {
    name: 'Karim Benali',
    role: 'Architecte',
    text: 'Cabinet moderne, accueil irréprochable, et soins réalisés avec beaucoup de précision.',
    featured: true,
  },
  {
    name: 'Nadia Chraibi',
    role: 'Médecin spécialiste',
    text: 'J’ai particulièrement apprécié la rigueur, l’hygiène et la qualité du suivi.',
  },
];

const faqs = [
  {
    question: 'Combien coûte une première consultation ?',
    answer:
      'La consultation initiale est à 300 DH. Elle comprend un examen complet et un plan de traitement personnalisé.',
  },
  {
    question: 'Les soins sont-ils remboursés par les mutuelles ?',
    answer:
      'Oui, une partie des soins conservateurs peut être prise en charge. Nous vous aidons à préparer les documents nécessaires.',
  },
  {
    question: 'Combien de temps dure un blanchiment ?',
    answer:
      "En général, une séance dure entre 60 et 90 minutes selon le protocole choisi et l'état initial des dents.",
  },
  {
    question: 'Prenez-vous les urgences dentaires ?',
    answer:
      'Oui, des créneaux d’urgence sont réservés chaque jour pour les douleurs, infections et traumatismes.',
  },
];

const Home = () => {
  const navigate = useNavigate();
  const [openFaq, setOpenFaq] = useState(0);

  return (
    <div className="home-page">
      <section className="hero-section">
        <div className="container hero-grid">
          <div className="hero-content">
            <span className="section-badge">Excellence certifiée</span>

            <h1 className="hero-title">
              Votre <span>sourire</span>,
              <br />
              notre passion
            </h1>

            <p className="hero-text">
              Des soins dentaires d’exception dans un environnement apaisant,
              lumineux et raffiné. Notre équipe vous accompagne avec précision,
              douceur et technologies de pointe.
            </p>

            <div className="hero-stats">
              <div className="stat-card">
                <strong>20+</strong>
                <span>Années d’expérience</span>
              </div>
              <div className="stat-card">
                <strong>15K+</strong>
                <span>Patients satisfaits</span>
              </div>
              <div className="stat-card">
                <strong>98%</strong>
                <span>Taux de satisfaction</span>
              </div>
            </div>

            <div className="hero-actions">
              <button className="btn btn-primary" onClick={() => navigate('/contact')}>
                Prendre rendez-vous
              </button>
              <button className="btn btn-secondary" onClick={() => navigate('/services')}>
                Voir nos services
              </button>
            </div>
          </div>

          <div className="hero-visual">
            <div className="hero-image-card">
              <img
                src="https://images.unsplash.com/photo-1606811841689-23dfddce3e95?w=1200&h=900&fit=crop&q=90"
                alt="Cabinet dentaire moderne"
              />
            </div>

            <div className="floating-box floating-box-top">
              <h4>Équipe certifiée</h4>
              <p>Dentistes diplômés</p>
            </div>

            <div className="floating-box floating-box-bottom">
              <h4>Technologies avancées</h4>
              <p>Équipements de pointe</p>
            </div>
          </div>
        </div>
      </section>

      <section className="section section-light">
        <div className="container">
          <div className="section-heading">
            <span className="section-badge">Pourquoi nous choisir</span>
            <h2>L’excellence à votre service</h2>
            <p>
              Une approche complète qui allie expertise médicale, innovation et
              qualité d’accueil.
            </p>
          </div>

          <div className="features-grid">
            {features.map((item) => (
              <article className="info-card" key={item.title}>
                <div className="icon-box">{item.icon}</div>
                <h3>{item.title}</h3>
                <p>{item.text}</p>
              </article>
            ))}
          </div>
        </div>
      </section>

      <section className="section section-soft">
        <div className="container">
          <div className="section-heading">
            <span className="section-badge">Nos soins</span>
            <h2>Traitements d’exception</h2>
            <p>
              Des solutions esthétiques et médicales pensées pour votre confort
              et votre confiance.
            </p>
          </div>

          <div className="treatments-grid">
            {treatments.map((item) => (
              <article className="treatment-card" key={item.title}>
                <span className="card-tag">{item.tag}</span>
                <div className="icon-box">{item.icon}</div>
                <h3>{item.title}</h3>
                <p>{item.text}</p>
              </article>
            ))}
          </div>
        </div>
      </section>

      <section className="section section-light">
        <div className="container">
          <div className="section-heading">
            <span className="section-badge">Témoignages</span>
            <h2>Ce que disent nos patients</h2>
            <p>
              La confiance de nos patients reflète la qualité de notre
              accompagnement au quotidien.
            </p>
          </div>

          <div className="testimonials-grid">
            {testimonials.map((item) => (
              <article
                key={item.name}
                className={`testimonial-card ${item.featured ? 'featured' : ''}`}
              >
                <div className="testimonial-stars">★★★★★</div>
                <p className="testimonial-text">“{item.text}”</p>
                <div className="testimonial-author">
                  <strong>{item.name}</strong>
                  <span>{item.role}</span>
                </div>
              </article>
            ))}
          </div>
        </div>
      </section>

      <section className="section section-soft">
        <div className="container faq-container">
          <div className="section-heading">
            <span className="section-badge">Questions fréquentes</span>
            <h2>Tout ce que vous souhaitez savoir</h2>
            <p>
              Retrouvez les réponses aux questions les plus courantes avant
              votre visite.
            </p>
          </div>

          <div className="faq-list">
            {faqs.map((item, index) => {
              const isOpen = openFaq === index;

              return (
                <div className={`faq-item ${isOpen ? 'open' : ''}`} key={item.question}>
                  <button
                    className="faq-question"
                    onClick={() => setOpenFaq(isOpen ? null : index)}
                  >
                    <span>{item.question}</span>
                    <span className="faq-symbol">{isOpen ? '−' : '+'}</span>
                  </button>

                  {isOpen && <p className="faq-answer">{item.answer}</p>}
                </div>
              );
            })}
          </div>
        </div>
      </section>

      <section className="cta-section">
        <div className="container">
          <div className="cta-box">
            <div>
              <span className="section-badge">Votre premier pas</span>
              <h2>Prenez rendez-vous dès aujourd’hui</h2>
              <p>
                Consultation de diagnostic, accompagnement personnalisé et prise
                en charge rapide.
              </p>
            </div>

            <div className="cta-actions">
              <button className="btn btn-primary" onClick={() => navigate('/contact')}>
                Réserver ma consultation
              </button>
              <span className="cta-phone">+212 5 37 XX XX XX</span>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Home;
